%[text] # Estimate VRFB Rating
%[text] Specify ambient temperature value.
myVRFB.blkPath = "VaRedoxFlowBattery/Vanadium Redox Flow Battery";
myVRFB.ambient = simscape.Value(280,"K");
myVRFB.nomCurr = simscape.Value(30,"A");
myVRFB.nomFlow = simscape.Value(20,"lpm");
%[text] To estimate the VRFB efficiency on the test harness model, run the MATLAB function `getVRFBefficiency`.
myVRFB.eff = getVRFBefficiency(BlockPath=myVRFB.blkPath,... %[output:group:82770f05] %[output:9a31bac7]
                               AmbientTemperature=myVRFB.ambient,... %[output:9a31bac7]
                               NominalCurrent=myVRFB.nomCurr,... %[output:9a31bac7]
                               NominalFlowrate=myVRFB.nomFlow); %[output:group:82770f05] %[output:9a31bac7]
%[text] Calculate battery energy and power values.
myVRFB.rating = getVRFBrating(BlockPath=myVRFB.blkPath,...
                              NominalCurrent=myVRFB.nomCurr);
%[text] Display battery efficiency and ratings:
disp(strcat("**** VRFB Efficiency = ",num2str(round(myVRFB.eff,1)),"%.")); %[output:4466959c]
disp(strcat("**** VRFB kW         = ",num2str(round(value(myVRFB.rating.kW,"kW"),1)),"kW.")); %[output:9223e224]
disp(strcat("**** VRFB Ahr        = ",num2str(round(value(myVRFB.rating.ampHour,"A*hr"),1)),"Ahr.")); %[output:5e6e174d]

